import { useState, useEffect } from "react";
import { Contact, Wrench, Home, MapPin, Image as ImageIcon, TrendingUp } from "lucide-react";
const HERO_BG = "data:image/jpeg;base64,";

// ── Design tokens ──────────────────────────────────────────────────
const G = "#123524";
const BRASS = "#B08D57";
const R = 20;
const fmt = n => Math.round(Number(n || 0)).toLocaleString("sv-SE") + " kr";

// ── Exempeldata ──────────────────────────────────────────────────
const properties = [
  { id: 1, name: "Kungsgatan 16", address: "Kungsgatan 16, Nora", cover_image_url: "https://picsum.photos/seed/rolandhem1/700/500" },
  { id: 2, name: "Kungsgatan 39", address: "Kungsgatan 39, Nora", cover_image_url: "https://picsum.photos/seed/rolandhem2/700/500" },
  { id: 3, name: "Storgatan 4", address: "Storgatan 4, Nora", cover_image_url: null },
];
const tenants = [
  { id: 1, property_id: 1 }, { id: 2, property_id: 1 }, { id: 3, property_id: 1 }, { id: 4, property_id: 1 },
  { id: 5, property_id: 2 }, { id: 6, property_id: 2 }, { id: 7, property_id: 2 },
  { id: 8, property_id: 3 }, { id: 9, property_id: 3 },
];
const issues = [
  { id: 1, property_id: 1, status: "ny" },
  { id: 2, property_id: 2, status: "pågående" },
];
const totalRentMon = 284500;
const totalRentYear = totalRentMon * 12;
const openIssues = issues.filter(i => i.status !== "åtgärdad").length;
const FRAUNCES = "'Fraunces', Georgia, serif";

function greetingNow() {
  const m = new Date().getHours() * 60 + new Date().getMinutes();
  if (m < 5*60) return "God natt";
  if (m < 9*60+30) return "God morgon";
  if (m < 11*60+30) return "God förmiddag";
  if (m < 14*60) return "God dag";
  if (m < 17*60) return "God eftermiddag";
  return "God kväll";
}

function useStyrranta() {
  const [rate, setRate] = useState(null);
  const [error, setError] = useState(false);
  useEffect(() => {
    fetch("https://api.riksbank.se/swea/v1/Observations/Latest/ByGroup/2")
      .then(r => r.json())
      .then(list => {
        const r = (list || []).find(x => x.seriesId === "SECBREPOEFF");
        if (r) setRate(r); else setError(true);
      })
      .catch(() => setError(true));
  }, []);
  return { rate, error };
}

function StyrrantaCard() {
  const { rate, error } = useStyrranta();
  return (
    <div style={{ background: "#fff", border: "1px solid #EAE7DF", borderRadius: 16, padding: "16px 20px", marginBottom: 26, display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16 }}>
      <div>
        <div style={{ fontSize: 11, color: "#84887E", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 6 }}>Styrränta (Riksbanken)</div>
        {rate ? (
          <>
            <div style={{ fontSize: 22, fontWeight: 800, color: G }}>{Number(rate.value).toFixed(2).replace(".", ",")}%</div>
            <div style={{ fontSize: 11, color: "#9ca3af", marginTop: 3 }}>Gäller från {new Date(rate.date).toLocaleDateString("sv-SE")} &middot; Källa: Riksbanken</div>
          </>
        ) : error ? (
          <div style={{ fontSize: 12, color: "#aaa" }}>Kunde inte hämta styrräntan just nu</div>
        ) : (
          <div style={{ fontSize: 12, color: "#ccc" }}>Hämtar...</div>
        )}
      </div>
      <TrendingUp size={22} color={BRASS} style={{ flexShrink: 0 }} />
    </div>
  );
}

function StatCard({ icon, label, value, color }) {
  return (
    <div style={{ background: "#fff", border: "1px solid #EAE7DF", borderRadius: 16, padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, color: "#84887E", fontWeight: 700, textTransform: "uppercase", marginBottom: 6 }}>{icon} {label}</div>
      <div style={{ fontSize: 19, fontWeight: 800, color: color || "#111" }}>{value}</div>
    </div>
  );
}
function StatRow() {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "repeat(2,1fr)", gap: 12, marginBottom: 26 }}>
      <StatCard icon={<Contact size={12} />} label="Hyresgäster" value={tenants.length} />
      <StatCard icon={<Wrench size={12} />} label="Öppna ärenden" value={openIssues} color={openIssues > 0 ? "#B5651D" : "#22c55e"} />
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════
// FÖRSLAG 1 — Premium hero + fotogalleri (Fraunces, mässing, kollage)
// ═══════════════════════════════════════════════════════════════
function Forslag1({ d }) {
  const photos = properties.filter(p => p.cover_image_url).slice(0, 3);
  const slots = [0, 1, 2];
  return (
    <>
      <div style={{ position: "relative", overflow: "hidden", borderRadius: R + 4, background: G, padding: d ? "36px 40px" : "26px 22px", marginBottom: 20, display: "flex", flexDirection: d ? "row" : "column", gap: d ? 36 : 24, alignItems: d ? "center" : "stretch", boxShadow: "0 20px 50px rgba(0,0,0,0.18)" }}>
        <img src={HERO_BG} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover", opacity: 0.6 }} />
        <div style={{ position: "absolute", inset: 0, background: `linear-gradient(115deg, ${G} 0%, rgba(18,53,36,0.9) 35%, rgba(11,33,24,0.45) 72%, rgba(11,33,24,0.22) 100%)` }} />
        <div style={{ position: "relative", flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 11.5, fontWeight: 700, color: BRASS, textTransform: "uppercase", letterSpacing: "0.14em", marginBottom: 10 }}>{greetingNow()}</div>
          <div style={{ fontFamily: FRAUNCES, fontSize: d ? 32 : 24, fontWeight: 600, color: "#fff", lineHeight: 1.15, marginBottom: 22, maxWidth: 420 }}>Rolandhem Fastigheter</div>
          <div style={{ fontSize: 12, fontWeight: 600, color: "rgba(255,255,255,0.55)", textTransform: "uppercase", letterSpacing: "0.07em", marginBottom: 6 }}>Hyresintäkt / mån</div>
          <div style={{ fontFamily: FRAUNCES, fontSize: d ? 52 : 38, fontWeight: 600, color: "#fff", letterSpacing: "-0.01em", lineHeight: 1 }}>{fmt(totalRentMon)}</div>
          <div style={{ height: 1, width: 64, background: BRASS, margin: "18px 0 16px", opacity: 0.7 }} />
          <div style={{ display: "flex", flexWrap: "wrap", gap: "8px 22px", fontSize: 12.5, color: "rgba(255,255,255,0.72)" }}>
            <span>{fmt(totalRentYear)} / år</span>
            <span>&middot;&nbsp; {tenants.length} hyresgäster</span>
            <span>&middot;&nbsp; {properties.length} fastigheter</span>
            <span style={{ color: openIssues > 0 ? "#f0b884" : "rgba(255,255,255,0.72)" }}>&middot;&nbsp; {openIssues} öppna ärenden</span>
          </div>
        </div>
        {d && (
          <div style={{ position: "relative", width: 220, height: 170, flexShrink: 0 }}>
            {slots.map(i => {
              const p = photos[i];
              const rot = [-6, 4, -2][i], z = [1, 2, 3][i], left = [0, 58, 30][i], top = [30, 8, 46][i];
              return (
                <div key={i} style={{ position: "absolute", left, top, width: 120, height: 100, borderRadius: 12, overflow: "hidden", transform: `rotate(${rot}deg)`, boxShadow: "0 14px 28px rgba(0,0,0,0.35)", border: "3px solid rgba(255,255,255,0.9)", zIndex: z, background: p ? "#0B2118" : `linear-gradient(135deg,#1c4432,${G})` }}>
                  {p ? <img src={p.cover_image_url} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}><Home size={22} color="rgba(255,255,255,0.35)" /></div>}
                </div>
              );
            })}
          </div>
        )}
      </div>
      <StatRow />
      <StyrrantaCard />
      <div style={{ marginBottom: 10 }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 10, marginBottom: 12 }}>
          <h3 style={{ fontFamily: FRAUNCES, fontSize: 17, fontWeight: 600, color: "#0F1512", margin: 0 }}>Dina fastigheter</h3>
          <span style={{ fontSize: 11.5, color: "#9ca3af" }}>{properties.length} st</span>
        </div>
        <div style={{ display: "flex", gap: 14, overflowX: "auto", paddingBottom: 6 }}>
          {properties.map(p => {
            const tCount = tenants.filter(t => t.property_id === p.id).length;
            const open = issues.filter(i => i.property_id === p.id && i.status !== "åtgärdad").length;
            return (
              <div key={p.id} style={{ borderRadius: 16, overflow: "hidden", background: "#fff", border: "1px solid #EAE7DF", flexShrink: 0, width: 230 }}>
                <div style={{ position: "relative", height: 120, background: p.cover_image_url ? "#0B2118" : `linear-gradient(135deg,#1c4432,${G})` }}>
                  {p.cover_image_url ? <img src={p.cover_image_url} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}><Home size={26} color="rgba(255,255,255,0.3)" /></div>}
                  <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(0,0,0,0.55), transparent 60%)" }} />
                  <div style={{ position: "absolute", left: 14, bottom: 10, right: 14, color: "#fff" }}>
                    <div style={{ fontFamily: FRAUNCES, fontWeight: 600, fontSize: 15.5 }}>{p.name}</div>
                    {p.address && <div style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11, opacity: 0.82, marginTop: 2 }}><MapPin size={10} />{p.address.split(",")[0]}</div>}
                  </div>
                </div>
                <div style={{ padding: "10px 14px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                  <div style={{ display: "flex", gap: 14, fontSize: 11.5, color: "#6b6f68" }}>
                    <span style={{ display: "flex", alignItems: "center", gap: 5 }}><Contact size={12} /> {tCount}</span>
                    <span style={{ display: "flex", alignItems: "center", gap: 5, color: open > 0 ? "#B5651D" : "#6b6f68" }}><Wrench size={12} /> {open}</span>
                  </div>
                  <span style={{ color: BRASS, fontSize: 13 }}>&rsaquo;</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </>
  );
}

// ═══════════════════════════════════════════════════════════════
// FÖRSLAG 2 — Befintlig layout, orörd, med en stilfull bildruta intill
// ═══════════════════════════════════════════════════════════════
function Forslag2({ d }) {
  const cover = properties.find(p => p.cover_image_url);
  return (
    <>
      <div style={{ display: "flex", flexDirection: d ? "row" : "column", gap: 14, marginBottom: 14 }}>
        {/* Exakt originalkortet — text, storlek, färg oförändrat */}
        <div style={{ background: G, color: "#fff", borderRadius: R, padding: "26px 26px 22px", flex: d ? "1 1 60%" : "none" }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: "rgba(255,255,255,0.62)", textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 8 }}>Hyresintäkt / mån</div>
          <div style={{ fontSize: d ? 44 : 34, fontWeight: 800, letterSpacing: "-0.02em", lineHeight: 1 }}>{fmt(totalRentMon)}</div>
          <div style={{ fontSize: 13, color: "rgba(255,255,255,0.58)", marginTop: 10 }}>{fmt(totalRentYear)} / år &middot; {tenants.length} hyresgäster &middot; {properties.length} fastigheter</div>
        </div>
        {/* Ny bildruta — stilfullt inramad, samma höjd som originalkortet, mässingskant */}
        <div style={{ position: "relative", flex: d ? "1 1 40%" : "none", height: d ? "auto" : 160, borderRadius: R, overflow: "hidden", border: `1px solid ${BRASS}55` }}>
          {cover ? <img src={cover.cover_image_url} alt={cover.name} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
            : <div style={{ width: "100%", height: "100%", background: "#eee" }} />}
          <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(0,0,0,0.5), transparent 55%)" }} />
          <div style={{ position: "absolute", left: 16, bottom: 12, color: "#fff" }}>
            <div style={{ fontSize: 10.5, fontWeight: 700, color: BRASS, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 2 }}>Senast tillagd</div>
            <div style={{ fontWeight: 700, fontSize: 14 }}>{cover?.name}</div>
          </div>
        </div>
      </div>
      <StatRow />
    </>
  );
}

// ═══════════════════════════════════════════════════════════════
// FÖRSLAG 3 — Editorial split-hero: stor bild med text ovanpå
// ═══════════════════════════════════════════════════════════════
function Forslag3({ d }) {
  const cover = properties.find(p => p.cover_image_url);
  return (
    <>
      <div style={{ position: "relative", borderRadius: R + 4, overflow: "hidden", marginBottom: 20, height: d ? 320 : 260, boxShadow: "0 20px 50px rgba(0,0,0,0.18)" }}>
        {cover && <img src={cover.cover_image_url} alt="" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} />}
        <div style={{ position: "absolute", inset: 0, background: `linear-gradient(100deg, ${G}f2 0%, ${G}c0 32%, rgba(11,33,24,0.15) 60%, rgba(11,33,24,0.05) 100%)` }} />
        <div style={{ position: "absolute", left: d ? 40 : 22, top: 0, bottom: 0, display: "flex", flexDirection: "column", justifyContent: "center", maxWidth: d ? 340 : 260 }}>
          <div style={{ fontSize: 11.5, fontWeight: 700, color: BRASS, textTransform: "uppercase", letterSpacing: "0.14em", marginBottom: 10 }}>{greetingNow()}</div>
          <div style={{ fontFamily: FRAUNCES, fontSize: d ? 30 : 22, fontWeight: 600, color: "#fff", lineHeight: 1.15, marginBottom: 20 }}>Rolandhem Fastigheter</div>
          <div style={{ fontFamily: FRAUNCES, fontSize: d ? 46 : 32, fontWeight: 600, color: "#fff", letterSpacing: "-0.01em", lineHeight: 1, marginBottom: 8 }}>{fmt(totalRentMon)}</div>
          <div style={{ fontSize: 12, color: "rgba(255,255,255,0.7)", marginBottom: 18 }}>Hyresintäkt / mån &middot; {fmt(totalRentYear)} / år</div>
          <div style={{ display: "flex", gap: 18, fontSize: 12, color: "rgba(255,255,255,0.75)" }}>
            <span>{tenants.length} hyresgäster</span>
            <span>{properties.length} fastigheter</span>
            <span style={{ color: openIssues > 0 ? "#f0b884" : "rgba(255,255,255,0.75)" }}>{openIssues} öppna ärenden</span>
          </div>
        </div>
        <div style={{ position: "absolute", right: 18, bottom: 14, fontSize: 10.5, color: "rgba(255,255,255,0.65)", display: "flex", alignItems: "center", gap: 5 }}>
          <ImageIcon size={11} /> {cover?.name}
        </div>
      </div>
      <StatRow />
    </>
  );
}

const TABS = [
  { key: "f1", label: "Förslag 1 · Premium hero + galleri", render: Forslag1 },
  { key: "f2", label: "Förslag 2 · Befintlig layout + bildruta", render: Forslag2 },
  { key: "f3", label: "Förslag 3 · Editorial split-hero", render: Forslag3 },
];

export default function OversiktForslag() {
  const [tab, setTab] = useState("f1");
  const [desktop, setDesktop] = useState(true);
  const Active = TABS.find(t => t.key === tab).render;

  return (
    <div style={{ minHeight: "100vh", background: "#FAF8F3", fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,500;9..144,600;9..144,700&display=swap');`}</style>

      <div style={{ position: "sticky", top: 0, zIndex: 10, background: "#FAF8F3", borderBottom: "1px solid #EAE7DF", padding: "14px 20px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 10, maxWidth: 800, margin: "0 auto" }}>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
            {TABS.map(t => (
              <button key={t.key} onClick={() => setTab(t.key)} style={{ padding: "7px 14px", borderRadius: 999, border: "1px solid " + (tab === t.key ? G : "#ddd"), background: tab === t.key ? G : "#fff", color: tab === t.key ? "#fff" : "#555", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>{t.label}</button>
            ))}
          </div>
          <div style={{ display: "flex", gap: 6 }}>
            <button onClick={() => setDesktop(true)} style={{ padding: "6px 12px", borderRadius: 8, border: "1px solid " + (desktop ? G : "#ddd"), background: desktop ? G : "#fff", color: desktop ? "#fff" : "#555", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>Desktop</button>
            <button onClick={() => setDesktop(false)} style={{ padding: "6px 12px", borderRadius: 8, border: "1px solid " + (!desktop ? G : "#ddd"), background: !desktop ? G : "#fff", color: !desktop ? "#fff" : "#555", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>Mobil</button>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: desktop ? 760 : 380, margin: "0 auto", padding: "24px 20px 60px" }}>
        <Active d={desktop} />
      </div>
    </div>
  );
}
